const items = $input.all();
const sourceData = $('Code: RSS Sources').all();

// Yesterday in JST (UTC+9)
const jstOffset = 9 * 60 * 60 * 1000;
const nowJst = new Date(Date.now() + jstOffset);
const y = new Date(nowJst);
y.setUTCDate(y.getUTCDate() - 1);
const startUtc = new Date(Date.UTC(y.getUTCFullYear(), y.getUTCMonth(), y.getUTCDate()) - jstOffset);
const endUtc = new Date(startUtc.getTime() + 86400000);

return items
  .filter(item => {
    const pub = new Date(item.json.pubDate || item.json.isoDate || '');
    return pub >= startUtc && pub < endUtc;
  })
  .map(item => {
    const idx = typeof item.pairedItem === 'number'
      ? item.pairedItem
      : (item.pairedItem?.item ?? 0);
    const source = sourceData[idx]?.json?.source ?? 'Unknown';
    return {
      json: {
        title:       item.json.title ?? '',
        url:         item.json.link  ?? item.json.url ?? '',
        source,
        publishedAt: item.json.pubDate || item.json.isoDate || '',
        rawContent:  item.json.contentSnippet || item.json.content || item.json.description || '',
      }
    };
  });

const claudeRes = $input.first().json;
const article  = $('Split In Batches').item.json;

const text = claudeRes.content?.[0]?.text ?? '';
let parsed = {};
try {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
} catch (_) {}

return [{
  json: {
    title:       article.title,
    url:         article.url,
    source:      article.source,
    publishedAt: article.publishedAt,
    rawContent:  article.rawContent,
    summary:     [parsed.what, parsed.why, parsed.who].filter(Boolean).join(' '),
    importance:  parsed.importance ?? 'medium',
    tags:        Array.isArray(parsed.tags) ? parsed.tags : [],
    createdAt:   new Date().toISOString(),
  }
}];

const items = $input.all();
const articles = items
  .filter(item => item.json.document)
  .map(item => {
    const f = item.json.document.fields;
    return {
      title:      f.title?.stringValue ?? '',
      source:     f.source?.stringValue ?? '',
      summary:    f.summary?.stringValue ?? '',
      importance: f.importance?.stringValue ?? 'medium',
      docId:      item.json.document.name.split('/').pop(),
    };
  });
if (articles.length === 0) return [{ json: { skip: true } }];
const jstOffset = 9 * 60 * 60 * 1000;
const nowJst = new Date(Date.now() + jstOffset);
const yJst = new Date(nowJst);
yJst.setUTCDate(yJst.getUTCDate() - 1);
const dd = d => String(d).padStart(2, '0');
const dateId = yJst.getUTCFullYear() + '-' + dd(yJst.getUTCMonth() + 1) + '-' + dd(yJst.getUTCDate());
const list = articles.map((a, i) => (i + 1) + '. [' + a.importance + '] ' + a.title + ' (' + a.source + '): ' + a.summary).join('\n');
const prompt = '今日収集した' + articles.length + '件のAI記事のトレンドを分析してください。\n\n記事:\n' + list + '\n\nJSONのみで出力:\n{"summary":"トレンドの方向性(200字以内)","keyTopics":["テーマ1","テーマ2","テーマ3"]}';
return [{ json: { dateId, articleCount: articles.length, articleIds: articles.map(a => a.docId), prompt } }];

const claudeRes = $input.first().json;
const meta = $('Code: Daily Prompt').item.json;
const text = claudeRes.content?.[0]?.text ?? '';
let parsed = {};
try {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
} catch (_) {}
return [{ json: { dateId: meta.dateId, date: meta.dateId, summary: parsed.summary ?? '', keyTopics: Array.isArray(parsed.keyTopics) ? parsed.keyTopics : [], articleCount: meta.articleCount, articleIds: meta.articleIds ?? [], createdAt: new Date().toISOString() } }];
